import { useEffect, useState } from 'react';
import { getAllMovements, getProduits } from '../services/stockApi';
import { Search } from 'lucide-react';
import MovementBadge from '../components/MovementBadge';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

export default function Movements() {
  const [movements, setMovements] = useState([]);
  const [produits,  setProduits]  = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [search,    setSearch]    = useState('');
  const [filterType, setFilterType] = useState('');

  useEffect(() => {
    Promise.all([getAllMovements(), getProduits()])
      .then(([m, p]) => { setMovements(m.data); setProduits(p.data); })
      .catch(() => toast.error('Erreur chargement'))
      .finally(() => setLoading(false));
  }, []);

  const filtered = movements.filter(m => {
    const matchSearch = !search ||
      m.productName.toLowerCase().includes(search.toLowerCase()) ||
      m.warehouseName.toLowerCase().includes(search.toLowerCase());
    const matchType = !filterType || m.type === filterType;
    return matchSearch && matchType;
  });

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h2>Historique des mouvements</h2>
          <p>{movements.length} mouvement(s) enregistré(s)</p>
        </div>
      </div>

      <div className="toolbar">
        <div className="search-box">
          <Search />
          <input placeholder="Rechercher produit, entrepôt…"
                 value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <select value={filterType} onChange={e => setFilterType(e.target.value)}
                style={{ background: 'var(--bg-2)', border: '1px solid var(--border)',
                         color: 'var(--text)', padding: '8px 12px', borderRadius: 8, fontSize: 13.5 }}>
          <option value="">Tous les types</option>
          <option value="ENTREE">Entrée</option>
          <option value="SORTIE">Sortie</option>
          <option value="TRANSFERT_ENTRANT">Transfert entrant</option>
          <option value="TRANSFERT_SORTANT">Transfert sortant</option>
        </select>
      </div>

      {loading ? <Spinner /> : (
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Date & heure</th>
                <th>Produit</th>
                <th>Entrepôt</th>
                <th>Type</th>
                <th>Quantité</th>
                <th>Note</th>
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 && (
                <tr><td colSpan={6} style={{ textAlign: 'center', color: 'var(--text-muted)', padding: 40 }}>
                  Aucun mouvement trouvé
                </td></tr>
              )}
              {filtered.map(m => (
                <tr key={m.movementId}>
                  <td style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>
                    {new Date(m.movementDate).toLocaleString('fr-FR')}
                  </td>
                  <td style={{ fontWeight: 500 }}>{m.productName}</td>
                  <td>{m.warehouseName}</td>
                  <td><MovementBadge type={m.type} /></td>
                  <td><span className="qty">{m.quantity}</span></td>
                  <td style={{ color: 'var(--text-muted)', fontSize: 12.5 }}>{m.note || '—'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
